	initialVal := int(grid[0][0])
	dp[0][0][initialVal] = true

	// Iterate through the grid
	for i := 0; i < M; i++ {
		for j := 0; j < N; j++ {
			if i == 0 && j == 0 {
				continue
			}

			currentVal := int(grid[i][j])

			// 1. Check path from above (i-1, j)
