						newXOR := x ^ currentVal
						dp[i][j][newXOR] = true
					}
				}
			}

			// 2. Check path from left (i, j-1)
			if j > 0 {
				for x := 0; x < MaxXOR; x++ {
					if dp[i][j-1][x] {
						newXOR := x ^ currentVal
						dp[i][j][newXOR] = true
					}
				}
			}
		}
	}

	// Find the minimum achievable XOR sum at (M-1, N-1)
