				if (maskLeft>>k)&1 == 1 {
					newXor := k ^ currentGridVal
					currentMask |= (1 << newXor)
				}
			}
			dp[i][j] = currentMask
		}
	}

	// The result is the minimum k such that the k-th bit of dp[M-1][N-1] is set.
	return findMinXOR(dp[M-1][N-1])
}
